    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    2,
    'Climbing Flexibility - 2w 3x/wk',
    'climbing',
    3,
    60,
    ARRAY['Improve flexibility', 'Enhance body awareness']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Climbing Flexibility'
ON CONFLICT DO NOTHING;

